from flask import Flask, request
import re

app = Flask(__name__)

def validate_file_id(file_id):
    if not re.match("^[0-9]+$", file_id):
        raise ValueError('Invalid file ID. Only positive integers are allowed.')

@app.route('/files/<int:file_id>', methods=['DELETE'])
def delete_file(file_id):
    # Validate input
    validate_file_id(file_id)

    # Simulate a database operation to delete the file record
    print(f"Deleting file with ID {file_id}")

    return '', 200

if __name__ == '__main__':
    app.run(debug=True)
